SELECT id, tenant_code, name, description, type, enabled, expire_at, is_deleted, created_at, updated_at
FROM tenant
WHERE is_deleted = FALSE

    AND (tenant_code ILIKE CONCAT('%', #{keyword}, '%') OR name ILIKE CONCAT('%', #{keyword}, '%'))


    AND type = #{type}



        AND enabled = TRUE AND (expire_at IS NULL OR expire_at > NOW())
        AND enabled = FALSE AND (expire_at IS NULL OR expire_at > NOW())
        AND expire_at IS NOT NULL AND expire_at <= NOW()



    AND expire_at >= #{expireFrom}


    AND expire_at <= #{expireTo}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM tenant
WHERE is_deleted = FALSE

    AND (tenant_code ILIKE CONCAT('%', #{keyword}, '%') OR name ILIKE CONCAT('%', #{keyword}, '%'))


    AND type = #{type}



        AND enabled = TRUE AND (expire_at IS NULL OR expire_at > NOW())
        AND enabled = FALSE AND (expire_at IS NULL OR expire_at > NOW())
        AND expire_at IS NOT NULL AND expire_at <= NOW()



    AND expire_at >= #{expireFrom}


    AND expire_at <= #{expireTo}

SELECT id, tenant_code, name, description, type, enabled, expire_at, is_deleted, created_at, updated_at
FROM tenant
WHERE id = #{id}

